 1	import React, { Dispatch, FC, SetStateAction, useState } from 'react';
 2	
 3	import DropdownToggle from '@kubevirt-utils/components/toggles/DropdownToggle';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { Dropdown, DropdownItem, DropdownList } from '@patternfly/react-core';
 6	
 7	import { InitialMigrationPolicyState } from '../../../../list/components/MigrationPolicyCreateForm/utils/utils';
 8	import {
 9	  EditMigrationPolicyInitialState,
10	  MigrationPolicyStateDispatch,
11	} from '../../../MigrationPolicyEditModal/utils/constants';
12	import { MigrationPolicyConfigurationOption } from '../../utils/constants';
13	
14	type MigrationPolicyConfigurationDropdownProps = {
15	  isDisabled: boolean;
16	  options: MigrationPolicyConfigurationOption;
17	  setState: Dispatch<SetStateAction<EditMigrationPolicyInitialState | InitialMigrationPolicyState>>;
18	  state: EditMigrationPolicyInitialState | InitialMigrationPolicyState;
19	};
20	
21	const MigrationPolicyConfigurationDropdown: FC<MigrationPolicyConfigurationDropdownProps> = ({
22	  isDisabled,
23	  options,
24	  setState,
25	  state,
26	}) => {
27	  const { t } = useKubevirtTranslation();
28	  const [isOpen, setIsOpen] = useState(false);
29	
30	  const handleOptionClick = (key: string, defaultValue: MigrationPolicyStateDispatch) => {
31	    setState((prev) => ({ ...prev, [key]: defaultValue }));
32	    setIsOpen(false);
33	  };
34	
35	  const onToggle = () => setIsOpen((prevIsOpen) => !prevIsOpen);
36	  return (
37	    <Dropdown
38	      toggle={DropdownToggle({
39	        children: t('Add configuration'),
40	        isDisabled,
41	        isExpanded: isOpen,
42	        onClick: onToggle,
43	      })}
44	      className="migration-policy__form-config-dropdown"
45	      data-test-id="migration-policies-configurations"
46	      isOpen={isOpen}
47	      onOpenChange={(open: boolean) => setIsOpen(open)}
48	    >
49	      <DropdownList>
50	        {Object.entries(options).map(([key, { defaultValue, description, label }]) => (
51	          <DropdownItem
52	            data-test-id={key}
53	            description={description}
54	            isDisabled={key in state}
55	            key={key}
56	            onClick={() => handleOptionClick(key, defaultValue)}
57	          >
58	            {label}
59	          </DropdownItem>
60	        ))}
61	      </DropdownList>
62	    </Dropdown>
63	  );
64	};
65	
66	export default MigrationPolicyConfigurationDropdown;

